#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

ll n, a[500005], b[500005];
ll t[1000005], tmp;

int lowbit(int k) {
    return k & (-k);
}

void add(int p) {
    while (p <= n) {
        t[p] += 1;
        p += lowbit(p);
    }
}

ll sum(int p) {
    ll s = 0;
    while (p >= 1) {
        s += t[p];
        p -= lowbit(p);
    }
    return s;
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        b[i] = a[i];
    }
    sort(b + 1, b + n + 1);
    tmp = unique(b + 1, b + n + 1) - b - 1;
    for (int i = 1; i <= n; i++) {
        a[i] = lower_bound(b + 1, b + tmp + 1, a[i]) - b;
    }
    ll ans = 0;
    for (int i = 1; i <= n; i++) {
        ans += sum(a[i]);
        add(a[i]);
    }
    cout << (n * (n - 1) / 2 - ans);
    return 0;
}
